Sure! An application can interact with the operating system (OS) to list all currently running processes through various methods depending on the operating system. Below are examples for both Unix-like systems (such as Linux and macOS) and Windows.

### Unix-Like Systems (Linux, macOS)

#### Using `ps` Command
The `ps` command is a powerful tool for listing running processes. Here’s how an application can use it:

1. **Using `ps` Directly**:
   ```sh
   ps aux
   ```
   This command lists all running processes along with their details.

2. **Reading `/proc` Filesystem**:
   Many Unix-like systems use the `/proc` filesystem to provide information about running processes. You can read the contents of `/proc` to get detailed information about processes.

   ```c
   #include <stdio.h>
   #include <dirent.h>
   #include <sys/types.h>
   #include <unistd.h>

   int main() {
       DIR *dir;
       struct dirent *ent;
       if ((dir = opendir("/proc")) != NULL) {
           while ((ent = readdir(dir)) != NULL) {
               // Skip "." and ".."
               if (strcmp(ent->d_name, ".") == 0 || strcmp(ent->d_name, "..") == 0)
                   continue;

               char path[256];
               snprintf(path, sizeof(path), "/proc/%s/status", ent->d_name);

               FILE *fp = fopen(path, "r");
               if (fp) {
                   printf("Process ID: %s\n", ent->d_name);
                   char line[256];
                   while (fgets(line, sizeof(line), fp)) {
                       if (line[0] == '\n')
                           break;
                       printf("%s", line);
                   }
                   fclose(fp);
               }
           }
           closedir(dir);
       } else {
           perror("opendir");
       }
       return 0;
   }
   ```

#### Using `procps` Library
The `procps` library provides a higher-level interface to the `/proc` filesystem, making it easier to interact with process information.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <procps/process.h>

int main() {
    struct proc_list *list = NULL;
    struct proc_info *info;

    // Get a list of all processes
    list = proc_list_all(PROC_ALL_PROCESS_INFO, &info);
    if (!list) {
        fprintf(stderr, "Failed to get process list\n");
        return 1;
    }

    // Iterate over the list and print process information
    while (list) {
        info = list->info;
        printf("PID: %d, Name: %s\n", info->pid, info->name);
        list = list->next;
    }

    // Free the allocated memory
    proc_free_list(list);

    return 0;
}
```

### Windows

#### Using `CreateToolhelp32Snapshot` and `Process32First/Process32Next`
Windows provides APIs to enumerate processes. Here’s how you can do it in C++:

```cpp
#include <windows.h>
#include <tlhelp32.h>
#include <iostream>

void ListProcesses() {
    HANDLE hProcessSnap;
    PROCESSENTRY32 pe32;

    // Take a snapshot of all processes in the system.
    hProcessSnap = CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, 0);
    if (hProcessSnap == INVALID_HANDLE_VALUE) {
        std::cerr << "CreateToolhelp32Snapshot failed" << std::endl;
        return;
    }

    // Set the size of the structure before using it.
    pe32.dwSize = sizeof(PROCESSENTRY32);

    // Retrieve information about the first process, and exit if unsuccessful
    if (!Process32First(hProcessSnap, &pe32)) {
        std::cerr << "Process32First failed" << std::endl;
        CloseHandle(hProcessSnap);
        return;
    }

    // Now walk the snapshot of processes.
    do {
        std::cout << "Process ID: " << pe32.th32ProcessID << ", Name: " << pe32.szExeFile << std::endl;
    } while (Process32Next(hProcessSnap, &pe32));

    // Clean up the snapshot object.
    CloseHandle(hProcessSnap);
}

int main() {
    ListProcesses();
    return 0;
}
```

### Summary
- **Unix-like Systems**: Use commands like `ps` or directly read the `/proc` filesystem.
- **Windows**: Use the `CreateToolhelp32Snapshot` API to enumerate processes.

These methods allow applications to interact with the OS to retrieve information about running processes, which can be useful for monitoring, debugging, or managing system resources.

